const batch = $json.body;
if (!batch || !Array.isArray(batch.records) || !batch.contract) throw new Error('Settlement batch is invalid');
const normalizedRows = batch.records.map((row) => ({
  transaction_id: row.transaction_id,
  account_id: row.account_id,
  settlement_date: row.settlement_date,
  currency: row.currency,
  amount_major: Number((row.amount_minor / 100).toFixed(3))
}));
const totals = new Map();
for (const row of normalizedRows) {
  const key = [row.account_id, row.settlement_date, row.currency].join('|');
  const current = totals.get(key) ?? { account_id: row.account_id, settlement_date: row.settlement_date, currency: row.currency, amount_major_total: 0, transaction_count: 0 };
  current.amount_major_total = Number((current.amount_major_total + row.amount_major).toFixed(3));
  current.transaction_count += 1;
  totals.set(key, current);
}
return [{ json: {
  batch_id: batch.batch_id,
  execution_id: String($execution.id),
  source_contract_version: batch.contract.version,
  transform_revision: 'settlement-normalizer-v3',
  normalized_rows: normalizedRows,
  currency_totals: [...totals.values()].sort((a, b) => a.currency.localeCompare(b.currency))
} }];
